import React, { useState, useEffect } from 'react';
import './App.css';
import { ReactComponent as LogoOnBlue } from './assets/logo_on_blue.svg';
import { ReactComponent as DesignElement } from './assets/design_element.svg';

const SAT_SCORES = ['1580', '1520', '1490', '1560', '1540', '1470', '1510', '1550', '1600', '1530'];
const STUDENT_NAMES = ['Alex', 'Priya', 'Jordan', 'Maya', 'Ethan', 'Sofia'];

const TitleSlide = () => {
  const [visible, setVisible] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 });

  useEffect(() => {
    const t = setTimeout(() => setVisible(true), 100);
    return () => clearTimeout(t);
  }, []);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    setMousePos({
      x: (e.clientX - rect.left) / rect.width,
      y: (e.clientY - rect.top) / rect.height,
    });
  };

  return (
    <div className="slide slide-title" onMouseMove={handleMouseMove}>
      {/* Animated gradient mesh */}
      <div className="title-gradient-orb title-orb--1" />
      <div className="title-gradient-orb title-orb--2" />
      <div className="title-gradient-orb title-orb--3" />

      {/* Grid overlay */}
      <div className="title-grid-overlay" />

      {/* Floating score bubbles */}
      <div className="title-floating-scores">
        {SAT_SCORES.map((score, i) => (
          <div
            key={i}
            className={`floating-score floating-score--${i}`}
            style={{
              '--parallax-x': `${(mousePos.x - 0.5) * (i % 2 === 0 ? 15 : -15)}px`,
              '--parallax-y': `${(mousePos.y - 0.5) * (i % 2 === 0 ? 10 : -10)}px`,
            }}
          >
            {score}
          </div>
        ))}
      </div>

      {/* Floating student avatars */}
      <div className="title-floating-avatars">
        {STUDENT_NAMES.map((name, i) => (
          <div
            key={i}
            className={`floating-avatar floating-avatar--${i}`}
            style={{
              '--parallax-x': `${(mousePos.x - 0.5) * (i % 2 === 0 ? -20 : 20)}px`,
              '--parallax-y': `${(mousePos.y - 0.5) * (i % 2 === 0 ? -12 : 12)}px`,
            }}
          >
            <div className="floating-avatar__img">
              <span>{name[0]}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Concentric circle accents */}
      <div className="title-bg-circle title-bg-circle--top-right">
        <DesignElement />
      </div>
      <div className="title-bg-circle title-bg-circle--bottom-left">
        <DesignElement />
      </div>

      {/* Main content */}
      <div className={`title-content ${visible ? 'visible' : ''}`}>
        <div className="title-badge">
          <span className="title-badge__dot" />
          SAT Excellence Program
        </div>

        <div className="title-logo">
          <LogoOnBlue />
        </div>

        <h1 className="title-heading">
          <span className="title-heading__line title-heading__line--1">SAT Presentation</span>
          <span className="title-heading__with">with</span>
          <span className="title-heading__line title-heading__line--2">TestPrep</span>
        </h1>

        <div className="title-divider">
          <span className="title-divider__line" />
          <span className="title-divider__diamond" />
          <span className="title-divider__line" />
        </div>

        <p className="title-subtitle">
          Building Your Roadmap to Your Dream University &amp; Major
        </p>

        <div className="title-stats">
          <div className="title-stat">
            <span className="title-stat__number">200+</span>
            <span className="title-stat__label">Avg Score Increase</span>
          </div>
          <div className="title-stat__separator" />
          <div className="title-stat">
            <span className="title-stat__number">98%</span>
            <span className="title-stat__label">Student Satisfaction</span>
          </div>
          <div className="title-stat__separator" />
          <div className="title-stat">
            <span className="title-stat__number">1500+</span>
            <span className="title-stat__label">Students Coached</span>
          </div>
        </div>
      </div>

      {/* Bottom shine line */}
      <div className="title-shine" />
    </div>
  );
};

const slides = [
  TitleSlide,
];

function App() {
  const [current, setCurrent] = useState(0);

  const goNext = () => setCurrent((prev) => Math.min(prev + 1, slides.length - 1));
  const goPrev = () => setCurrent((prev) => Math.max(prev - 1, 0));

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowRight') goNext();
    if (e.key === 'ArrowLeft') goPrev();
  };

  return (
    <div className="presentation" tabIndex={0} onKeyDown={handleKeyDown}>
      <div
        className="slide-track"
        style={{ transform: `translateX(-${current * 100}vw)` }}
      >
        {slides.map((Slide, i) => (
          <Slide key={i} />
        ))}
      </div>

      <div className="nav-buttons">
        <button onClick={goPrev} disabled={current === 0}>←</button>
        <span>{current + 1} / {slides.length}</span>
        <button onClick={goNext} disabled={current === slides.length - 1}>→</button>
      </div>
    </div>
  );
}

export default App;
